/* style.css */

/* Reset et styles de base */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
}

body {
    background: linear-gradient(135deg, #6a11cb 0%, #2575fc 100%);
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 20px;
}

.container {
    width: 100%;
    max-width: 450px;
    background-color: white;
    border-radius: 20px;
    box-shadow: 0 15px 35px rgba(0, 0, 0, 0.2);
    overflow: hidden;
}

/* En-tête avec bascule entre connexion/inscription */
.auth-container .header {
    display: flex;
    position: relative;
    background-color: #f8f9fa;
    padding: 30px 40px 20px;
}

.header .title {
    flex: 1;
    text-align: center;
    padding: 15px 0;
    cursor: pointer;
    color: #6c757d;
    font-weight: 600;
    font-size: 1.4rem;
    transition: color 0.3s;
    z-index: 2;
}

.header .title.active {
    color: #2575fc;
}

.header .toggle-indicator {
    position: absolute;
    bottom: 0;
    left: 0;
    height: 4px;
    width: 50%;
    background-color: #2575fc;
    border-radius: 4px 4px 0 0;
    transition: transform 0.4s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

/* Styles des formulaires */
.auth-container .form {
    padding: 40px;
    display: none;
}

.auth-container .form.active {
    display: block;
    animation: fadeIn 0.5s ease-out;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(10px); }
    to { opacity: 1; transform: translateY(0); }
}

/* Groupes de champs */
.input-group {
    position: relative;
    margin-bottom: 25px;
}

.input-group i {
    position: absolute;
    left: 15px;
    top: 50%;
    transform: translateY(-50%);
    color: #6c757d;
    font-size: 1.1rem;
}

.input-group input {
    width: 100%;
    padding: 15px 15px 15px 50px;
    border: 2px solid #e9ecef;
    border-radius: 10px;
    font-size: 1rem;
    transition: all 0.3s;
}

.input-group input:focus {
    border-color: #2575fc;
    outline: none;
    box-shadow: 0 0 0 3px rgba(37, 117, 252, 0.1);
}

.input-group input.error {
    border-color: #dc3545;
}

.error-message {
    color: #dc3545;
    font-size: 0.85rem;
    margin-top: 5px;
    min-height: 20px;
    display: none;
}

.error-message.show {
    display: block;
}

/* Options (cases à cocher et liens) */
.options, .terms {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 25px;
}

.checkbox {
    display: flex;
    align-items: center;
    cursor: pointer;
    font-size: 0.9rem;
    color: #495057;
}

.checkbox input {
    margin-right: 8px;
    cursor: pointer;
}

.forgot-password {
    color: #2575fc;
    text-decoration: none;
    font-size: 0.9rem;
    transition: color 0.3s;
}

.forgot-password:hover {
    color: #6a11cb;
    text-decoration: underline;
}

.terms a {
    color: #2575fc;
    text-decoration: none;
}

.terms a:hover {
    text-decoration: underline;
}

/* Bouton de soumission */
.submit-btn {
    width: 100%;
    padding: 15px;
    background: linear-gradient(to right, #2575fc, #6a11cb);
    color: white;
    border: none;
    border-radius: 10px;
    font-size: 1.1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s;
    margin-bottom: 20px;
