### Gestion de l'interface utilisateur
Nous allons créer des fonctions pour basculer entre les formulaires et gérer les interactions utilisateur.

```javascript
// Références aux éléments du DOM
const loginTitle = document.getElementById('login-title');
const signupTitle = document.getElementById('signup-title');
const toggleIndicator = document.getElementById('toggle-indicator');
const loginForm = document.getElementById('login-form');
const signupForm = document.getElementById('signup-form');
const statusMessage = document.getElementById('status-message');

// Variables pour suivre l'état actuel
let isLoginMode = true;

// Fonction pour basculer entre les formulaires
function toggleForms() {
    isLoginMode = !isLoginMode;

    // Animation de l'indicateur
    toggleIndicator.style.transform = isLoginMode 
        ? 'translateX(0)' 
        : 'translateX(100%)';

    // Basculer les titres actifs
    loginTitle.classList.toggle('active', isLoginMode);
    signupTitle.classList.toggle('active', !isLoginMode);

    // Basculer les formulaires
    loginForm.classList.toggle('active', isLoginMode);
    signupForm.classList.toggle('active', !isLoginMode);

    // Réinitialiser les messages d'erreur
    clearErrorMessages();
    hideStatusMessage();
}

// Ajouter les écouteurs d'événements pour les titres
loginTitle.addEventListener('click', () => {
    if (!isLoginMode) toggleForms();
});

signupTitle.addEventListener('click', () => {
    if (isLoginMode) toggleForms();
});
```

### Validation des formulaires
Avant d'envoyer les données à Firebase, nous allons valider les entrées utilisateur côté client.

```javascript
// Fonctions de validation
function validateEmail(email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
}

function validatePassword(password) {
    // Au moins 8 caractères, une lettre majuscule, une minuscule et un chiffre
    const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d).{8,}$/;
    return passwordRegex.test(password);
}

function validateName(name) {
    return name.trim().length >= 2;
}

// Fonctions pour afficher/masquer les erreurs
function showError(elementId, message) {
    const errorElement = document.getElementById(elementId);
    errorElement.textContent = message;
    errorElement.classList.add('show');

    // Ajouter la classe d'erreur au champ correspondant
    const inputId = elementId.replace('-error', '');
    const inputElement = document.getElementById(inputId);
    if (inputElement) {
        inputElement.classList.add('error');
    }
}

function clearError(elementId) {
    const errorElement = document.getElementById(elementId);
    errorElement.textContent = '';
    errorElement.classList.remove('show');

    // Retirer la classe d'erreur du champ correspondant
    const inputId = elementId.replace('-error', '');
    const inputElement = document.getElementById(inputId);
    if (inputElement) {
        inputElement.classList.remove('error');
    }
}

function clearErrorMessages() {
    const errorMessages = document.querySelectorAll('.error-message');
    errorMessages.forEach(error => {
        error.textContent = '';
        error.classList.remove('show');
    });

    const errorInputs = document.querySelectorAll('.error');
    errorInputs.forEach(input => {
        input.classList.remove('error');
    });
}

// Fonctions pour afficher les messages de statut
function showStatusMessage(message, isSuccess) {
    statusMessage.textContent = message;
    statusMessage.className = 'status-message ' + (isSuccess ? 'success' : 'error');
}

function hideStatusMessage() {
    statusMessage.className = 'status-message';
}
