### Gestion de l'inscription
Maintenant, implémentons la logique pour créer un nouvel utilisateur dans Firebase.

```javascript
// Gestion du formulaire d'inscription
signupForm.addEventListener('submit', async function(e) {
    e.preventDefault();

    // Récupérer les valeurs des champs
    const name = document.getElementById('signup-name').value.trim();
    const email = document.getElementById('signup-email').value.trim();
    const password = document.getElementById('signup-password').value;
    const confirmPassword = document.getElementById('signup-confirm-password').value;
    const agreeTerms = document.getElementById('agree-terms').checked;

    // Réinitialiser les erreurs précédentes
    clearErrorMessages();

    // Validation
    let isValid = true;

    if (!validateName(name)) {
        showError('signup-name-error', 'Le nom doit contenir au moins 2 caractères');
        isValid = false;
    }

    if (!validateEmail(email)) {
        showError('signup-email-error', 'Veuillez entrer un email valide');
        isValid = false;
    }

    if (!validatePassword(password)) {
        showError('signup-password-error', 'Le mot de passe doit contenir au moins 8 caractères, une majuscule, une minuscule et un chiffre');
        isValid = false;
    }

    if (password !== confirmPassword) {
        showError('signup-confirm-password-error', 'Les mots de passe ne correspondent pas');
        isValid = false;
    }

    if (!agreeTerms) {
        showStatusMessage('Vous devez accepter les conditions d\'utilisation', false);
        isValid = false;
    }

    if (!isValid) return;

    // Désactiver le bouton pendant le traitement
    const submitBtn = signupForm.querySelector('.submit-btn');
    const originalText = submitBtn.textContent;
    submitBtn.textContent = 'Inscription en cours...';
    submitBtn.disabled = true;

    try {
        // Créer l'utilisateur avec Firebase Authentication
        const userCredential = await auth.createUserWithEmailAndPassword(email, password);
        const user = userCredential.user;

        // Enregistrer des informations supplémentaires dans la base de données
        await database.ref('users/' + user.uid).set({
            name: name,
            email: email,
            createdAt: new Date().toISOString()
        });

        // Afficher un message de succès
        showStatusMessage(`Inscription réussie ! Bienvenue ${name}`, true);

        // Réinitialiser le formulaire
        signupForm.reset();

        // Basculer automatiquement vers le formulaire de connexion après 2 secondes
        setTimeout(() => {
            if (!isLoginMode) toggleForms();
        }, 2000);

    } catch (error) {
        // Gérer les erreurs Firebase
        let errorMessage = 'Une erreur est survenue';

        switch (error.code) {
            case 'auth/email-already-in-use':
                errorMessage = 'Cet email est déjà utilisé';
                showError('signup-email-error', errorMessage);
                break;
            case 'auth/weak-password':
                errorMessage = 'Le mot de passe est trop faible';
                showError('signup-password-error', errorMessage);
                break;
            case 'auth/invalid-email':
                errorMessage = 'Email invalide';
                showError('signup-email-error', errorMessage);
                break;
            default:
                showStatusMessage(errorMessage + ': ' + error.message, false);
        }
    } finally {
        // Réactiver le bouton
        submitBtn.textContent = originalText;
        submitBtn.disabled = false;
    }
});
