// Gestion du formulaire de connexion
loginForm.addEventListener('submit', async function(e) {
    e.preventDefault();

    // Récupérer les valeurs des champs
    const email = document.getElementById('login-email').value.trim();
    const password = document.getElementById('login-password').value;
    const rememberMe = document.getElementById('remember-me').checked;

    // Réinitialiser les erreurs précédentes
    clearErrorMessages();
    hideStatusMessage();

    // Validation
    let isValid = true;

    if (!validateEmail(email)) {
        showError('login-email-error', 'Veuillez entrer un email valide');
        isValid = false;
    }

    if (password.length < 6) {
        showError('login-password-error', 'Le mot de passe doit contenir au moins 6 caractères');
        isValid = false;
    }

    if (!isValid) return;

    // Désactiver le bouton pendant le traitement
    const submitBtn = loginForm.querySelector('.submit-btn');
    const originalText = submitBtn.textContent;
    submitBtn.textContent = 'Connexion en cours...';
    submitBtn.disabled = true;

    try {
        // Configurer la persistance de la session
        const persistence = rememberMe 
            ? firebase.auth.Auth.Persistence.LOCAL 
            : firebase.auth.Auth.Persistence.SESSION;

        await auth.setPersistence(persistence);

        // Connecter l'utilisateur
        const userCredential = await auth.signInWithEmailAndPassword(email, password);
        const user = userCredential.user;

        // Récupérer les informations supplémentaires de l'utilisateur
        const userSnapshot = await database.ref('users/' + user.uid).once('value');
        const userData = userSnapshot.val();

        // Afficher un message de succès
        const userName = userData ? userData.name : email;
        showStatusMessage(`Connexion réussie ! Bienvenue ${userName}`, true);

        // Réinitialiser le formulaire
        loginForm.reset();

        // Redirection vers une page sécurisée après 2 secondes
        setTimeout(() => {
            window.location.href = 'dashboard.html'; // Page à créer
        }, 2000);

    } catch (error) {
        // Gérer les erreurs Firebase
        let errorMessage = 'Une erreur est survenue';

        switch (error.code) {
            case 'auth/user-not-found':
                errorMessage = 'Aucun compte associé à cet email';
                showError('login-email-error', errorMessage);
                break;
            case 'auth/wrong-password':
                errorMessage = 'Mot de passe incorrect';
                showError('login-password-error', errorMessage);
                break;
            case 'auth/invalid-email':
                errorMessage = 'Email invalide';
                showError('login-email-error', errorMessage);
                break;
            case 'auth/user-disabled':
                errorMessage = 'Ce compte a été désactivé';
                showStatusMessage(errorMessage, false);
                break;
            default:
                showStatusMessage(errorMessage + ': ' + error.message, false);
        }
    } finally {
        // Réactiver le bouton
        submitBtn.textContent = originalText;
        submitBtn.disabled = false;
    }
});
