// Connexion sociale (exemple avec Google)
document.querySelector('.social-btn.google').addEventListener('click', function() {
    const provider = new firebase.auth.GoogleAuthProvider();

    auth.signInWithPopup(provider)
        .then((result) => {
            // L'utilisateur est connecté avec Google
            const user = result.user;

            // Vérifier si c'est la première connexion
            if (result.additionalUserInfo.isNewUser) {
                // Enregistrer l'utilisateur dans la base de données
                database.ref('users/' + user.uid).set({
                    name: user.displayName,
                    email: user.email,
                    provider: 'google',
                    createdAt: new Date().toISOString()
                });
            }

            showStatusMessage(`Connexion réussie avec Google ! Bienvenue ${user.displayName}`, true);

            // Redirection après 2 secondes
            setTimeout(() => {
                window.location.href = 'dashboard.html';
            }, 2000);
        })
        .catch((error) => {
            showStatusMessage('Erreur de connexion avec Google: ' + error.message, false);
        });
});

// Pré-remplir l'email lors du basculement entre les formulaires
loginForm.addEventListener('focusout', function(e) {
    if (e.target.id === 'login-email') {
        const email = e.target.value.trim();
        if (validateEmail(email)) {
            // Stocker l'email pour pré-remplir le formulaire d'inscription
            localStorage.setItem('lastEmail', email);
        }
    }
});

// Pré-remplir l'email dans le formulaire d'inscription si disponible
window.addEventListener('load', function() {
    const lastEmail = localStorage.getItem('lastEmail');
    if (lastEmail && validateEmail(lastEmail)) {
        document.getElementById('signup-email').value = lastEmail;
    }
});

